<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                0X</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0209C004</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0X</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">04</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> /* GPIO1_GDIR_BASE */</span></span>
